# NEAR's public archival RPC — no apiKey required.
ACCOUNT_ID=root.near
BLOCK_ID=100000000

curl -sS "https://archival-rpc.mainnet.near.org"   -H 'content-type: application/json'   --data "$(jq -nc --arg account_id "$ACCOUNT_ID" --argjson block "$BLOCK_ID" '{
    jsonrpc:"2.0",id:"fastnear",method:"query",
    params:{request_type:"view_account",account_id:$account_id,block_id:$block}
  }')"   | jq '.result | {amount, storage_usage, block_height, block_hash}'

